commands.cmd:
raw=$(ss -tan) || { echo "ss failed" >&2; exit 1; }
printf '%s\n' "$raw" | awk '
  NR>1 {
    st=$1; total++
    if (st=="ESTAB") established++
    else if (st=="TIME-WAIT") time_wait++
    else if (st=="CLOSE-WAIT") close_wait++
    else if (st=="SYN-SENT") syn_sent++
    else if (st=="SYN-RECV") syn_recv++
    else if (st=="FIN-WAIT-1" || st=="FIN-WAIT-2") fin_wait++
    else if (st=="LISTEN") listen++
  }
  END{
    printf "{\"total\":%d,\"established\":%d,\"time_wait\":%d,\"close_wait\":%d,\"syn_sent\":%d,\"syn_recv\":%d,\"fin_wait\":%d,\"listen\":%d}",
      total, established, time_wait, close_wait, syn_sent, syn_recv, fin_wait, listen
  }' || exit 1
